@namespace Lumeo
@inject IComponentInteropService Interop
@implements IAsyncDisposable

<div id="@_containerId" data-slot="scrollspy" class="@CssClass" @attributes="AdditionalAttributes">
    <CascadingValue Value="_context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int Offset { get; set; }
    [Parameter] public bool Smooth { get; set; } = true;
    [Parameter] public string? ActiveId { get; set; }
    [Parameter] public EventCallback<string> ActiveIdChanged { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _containerId = LumeoIds.New("scrollspy");
    private ScrollspyContext _context = default!;
    private string? _currentActiveId;
    // Mirrors ONLY the last ActiveId supplied via the parameter (seeded in
    // OnInitialized, refreshed in OnParametersSet). It is never written from
    // scroll-driven (OnScrollspyUpdate) or click-driven (OnNavigate) updates, so
    // OnParametersSet can tell a genuine external set (ActiveId != this mirror)
    // apart from both our own ActiveIdChanged echo AND an unrelated re-render that
    // left ActiveId unchanged. Without this separation a scroll the consumer never
    // round-trips would make the next re-render force-scroll back to the param
    // value (Gantt-class state-on-data-change bug). Used for the UNCONTROLLED
    // (no ActiveIdChanged delegate) path only.
    private string? _lastParamActiveId;
    // CONTROLLED discriminator: the last value we pushed UP via ActiveIdChanged (also
    // re-synced whenever we adopt an authoritative ActiveId). A controlled parent
    // re-render that echoes back this exact value is safe to ignore (keep the
    // in-flight _currentActiveId); anything else — including a veto that re-renders
    // with the SAME ActiveId the parent had before our optimistic update — is an
    // authoritative assertion and must win (roll back).
    private string? _lastPushed;
    private bool _pendingProgrammaticScroll;
    // Last (Offset, Smooth) the JS observer was registered with. The JS closure
    // captures `offset` (and `smooth`) by value, so an Offset/Smooth change after
    // first render must tear the observer down and re-register, otherwise active-
    // section detection keeps using the stale initial Offset forever (lifecycle
    // bug #100). null = not yet registered.
    private (int Offset, bool Smooth)? _registeredOptions;

    private string CssClass => Cx.Merge("relative", Class);

    protected override void OnInitialized()
    {
        _currentActiveId = ActiveId;
        _lastParamActiveId = ActiveId;
        _lastPushed = ActiveId;
        _context = new ScrollspyContext(_currentActiveId, EventCallback.Factory.Create<string>(this, OnNavigate));
    }

    protected override void OnParametersSet()
    {
        // Two-way control input (#246): when the consumer sets ActiveId to a new
        // value, scroll that section into view (honouring Offset).
        if (ActiveIdChanged.HasDelegate)
        {
            // CONTROLLED: the parent owns the value. Echo of our own push
            // (ActiveId == _lastPushed) → keep the in-flight _currentActiveId.
            // Anything else (veto, normalization, external reset) is an
            // authoritative assertion and must win, even if it equals the value
            // the parent had before our optimistic local update.
            if (ActiveId != _lastPushed)
            {
                _lastPushed = ActiveId;
                if (!string.IsNullOrEmpty(ActiveId) && ActiveId != _currentActiveId)
                {
                    _currentActiveId = ActiveId;
                    _context = new ScrollspyContext(_currentActiveId, EventCallback.Factory.Create<string>(this, OnNavigate));
                    _pendingProgrammaticScroll = true;
                }
            }
        }
        else if (ActiveId != _lastParamActiveId)
        {
            // UNCONTROLLED: component owns the live value. Adopt the parameter
            // only when the parent genuinely changes it; a stale re-render that
            // re-supplies the same literal must not clobber a scroll/click update.
            _lastPushed = ActiveId;
            if (!string.IsNullOrEmpty(ActiveId) && ActiveId != _currentActiveId)
            {
                _currentActiveId = ActiveId;
                _context = new ScrollspyContext(_currentActiveId, EventCallback.Factory.Create<string>(this, OnNavigate));
                _pendingProgrammaticScroll = true;
            }
        }

        // Keep the uncontrolled discriminator pointing at the last ActiveId we observed.
        _lastParamActiveId = ActiveId;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Register on first render, and RE-register whenever Offset/Smooth change
        // afterwards: the JS observer captures those by value, so a runtime change
        // would otherwise be ignored (lifecycle bug #100). Tear down the previous
        // observer first so we don't leak a listener or double-fire.
        var options = (Offset, Smooth);
        if (_registeredOptions != options)
        {
            try
            {
                if (_registeredOptions is not null)
                {
                    await Interop.UnregisterScrollspy(_containerId);
                }
                await Interop.RegisterScrollspy(_containerId, Offset, Smooth, OnScrollspyUpdate);
                _registeredOptions = options;
            }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
        }

        if (_pendingProgrammaticScroll && _currentActiveId is not null)
        {
            _pendingProgrammaticScroll = false;
            try
            {
                await Interop.ScrollspyScrollTo(_containerId, _currentActiveId, Smooth, Offset);
            }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
        }
    }

    private async Task OnScrollspyUpdate(string? activeId)
    {
        if (_currentActiveId != activeId)
        {
            _currentActiveId = activeId;
            // Do NOT touch _lastParamActiveId here. It mirrors only the incoming
            // ActiveId parameter (set in OnInitialized/OnParametersSet), so a
            // scroll-driven update that the consumer never round-trips can't make
            // a later unrelated re-render look like an external ActiveId set and
            // force-scroll back to the param value. If the consumer DOES round-trip
            // the echo, the `ActiveId != _currentActiveId` guard in OnParametersSet
            // absorbs it (no redundant scroll), since _currentActiveId already
            // equals the echoed value.
            _context = new ScrollspyContext(_currentActiveId, EventCallback.Factory.Create<string>(this, OnNavigate));
            // Record _lastPushed BEFORE invoking ActiveIdChanged: a controlled
            // parent re-renders synchronously inside InvokeAsync, so OnParametersSet
            // must already see this value as "the value we just pushed" to
            // distinguish an accepted echo (keep in-flight state) from a veto
            // (parent kept its old value → roll back).
            _lastPushed = activeId ?? string.Empty;
            await ActiveIdChanged.InvokeAsync(activeId ?? string.Empty);
            await InvokeAsync(StateHasChanged);
        }
    }

    private async Task OnNavigate(string sectionId)
    {
        // Clicking a link scrolls (Offset-aware) AND reflects the selection back
        // through ActiveIdChanged so the bound value tracks clicks, not just
        // scroll. The scroll observer will also fire as the page moves, but
        // updating eagerly keeps a controlled consumer in sync immediately.
        await Interop.ScrollspyScrollTo(_containerId, sectionId, Smooth, Offset);
        if (_currentActiveId != sectionId)
        {
            _currentActiveId = sectionId;
            // As in OnScrollspyUpdate, _lastParamActiveId is left untouched: it
            // tracks only the consumer-supplied ActiveId parameter. A click that
            // isn't round-tripped into ActiveId must not be misread as an external
            // set on a later re-render (which would force-scroll back).
            _context = new ScrollspyContext(_currentActiveId, EventCallback.Factory.Create<string>(this, OnNavigate));
            // Record _lastPushed BEFORE invoking ActiveIdChanged — see OnScrollspyUpdate.
            _lastPushed = sectionId;
            await ActiveIdChanged.InvokeAsync(sectionId);
            await InvokeAsync(StateHasChanged);
        }
    }

    public async ValueTask DisposeAsync()
    {
        try
        {
            await Interop.UnregisterScrollspy(_containerId);
        }
        catch (JSDisconnectedException) { }
    }

    public record ScrollspyContext(string? ActiveId, EventCallback<string> OnNavigate);
}

@namespace Lumeo

<button data-slot="scrollspy-link"
        data-active="@(Context?.ActiveId == Target ? "true" : null)"
        aria-current="@(Context?.ActiveId == Target ? "location" : null)"
        class="@CssClass"
        @onclick="HandleClick"
        @attributes="AdditionalAttributes">
    @ChildContent
</button>

@code {
    [CascadingParameter] public Scrollspy.ScrollspyContext? Context { get; set; }
    [Parameter, EditorRequired] public string Target { get; set; } = "";
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge(Class);

    private async Task HandleClick()
    {
        if (Context is not null)
        {
            await Context.OnNavigate.InvokeAsync(Target);
        }
    }
}

@namespace Lumeo

<div id="@Id" data-scrollspy-section class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [Parameter, EditorRequired] public string Id { get; set; } = "";
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge(Class);
}
